f = open('c:/Users/WELMAN/Downloads/my_third_app/crawler_system/frontend/lib/features/notices/presentation/pages/notices_page.dart', 'a', encoding='utf-8')
dialog = '''\n\nclass _SnapshotViewerDialog extends StatefulWidget {\n  final String content;\n  final String? keywordToHighlight;\n\n  const _SnapshotViewerDialog({\n    required this.content,\n    this.keywordToHighlight,\n  });\n\n  @override\n  State<_SnapshotViewerDialog> createState() => _SnapshotViewerDialogState();\n}\n\nclass _SnapshotViewerDialogState extends State<_SnapshotViewerDialog> {\n  final GlobalKey _targetKey = GlobalKey();\n  final ScrollController _scrollController = ScrollController();\n\n  @override\n  void initState() {\n    super.initState();\n    WidgetsBinding.instance.addPostFrameCallback((_) {\n      if (widget.keywordToHighlight != null && widget.keywordToHighlight!.isNotEmpty && _targetKey.currentContext != null) {\n        Scrollable.ensureVisible(\n          _targetKey.currentContext!,\n          duration: const Duration(milliseconds: 300),\n          alignment: 0.2,\n        );\n      }\n    });\n  }\n\n  @override\n  void dispose() {\n    _scrollController.dispose();\n    super.dispose();\n  }\n\n  List<InlineSpan> _buildSpans(String text, String? keyword) {\n    if (keyword == null || keyword.isEmpty) {\n      return [TextSpan(text: text)];\n    }\n    final spans = <InlineSpan>[];\n    final lowerText = text.toLowerCase();\n    final lowerKeyword = keyword.toLowerCase();\n    int start = 0;\n    int indexOfMatch;\n    bool isFirst = true;\n\n    while ((indexOfMatch = lowerText.indexOf(lowerKeyword, start)) != -1) {\n      if (indexOfMatch > start) {\n        spans.add(TextSpan(text: text.substring(start, indexOfMatch)));\n      }\n      final kwText = text.substring(indexOfMatch, indexOfMatch + keyword.length);\n      \n      if (isFirst) {\n        spans.add(\n          WidgetSpan(\n            alignment: PlaceholderAlignment.middle,\n            child: Container(\n              key: _targetKey,\n              color: Colors.yellow,\n              child: Text(\n                kwText,\n                style: const TextStyle(color: Colors.red, fontWeight: FontWeight.bold),\n              ),\n            ),\n          ),\n        );\n        isFirst = false;\n      } else {\n        spans.add(\n          TextSpan(\n            text: kwText,\n            style: const TextStyle(\n              backgroundColor: Colors.yellow,\n              color: Colors.red,\n              fontWeight: FontWeight.bold,\n            ),\n          ),\n        );\n      }\n      start = indexOfMatch + keyword.length;\n    }\n    if (start < text.length) {\n      spans.add(TextSpan(text: text.substring(start)));\n    }\n    return spans;\n  }\n\n  @override\n  Widget build(BuildContext context) {\n    return AlertDialog(\n      title: const Text('快照内容'),\n      content: SizedBox(\n        width: 720,\n        child: Scrollbar(\n          controller: _scrollController,\n          interactive: true,\n          thumbVisibility: true,\n          child: SingleChildScrollView(\n            controller: _scrollController,\n            child: SelectableText.rich(\n              TextSpan(\n                children: _buildSpans(widget.content, widget.keywordToHighlight),\n              ),\n            ),\n          ),\n        ),\n      ),\n      actions: [\n        TextButton(\n          onPressed: () => Navigator.of(context).pop(),\n          child: const Text('关闭'),\n        ),\n      ],\n    );\n  }\n}'''
f.write(dialog)
f.close()
